import { task } from "@trigger.dev/sdk/v3";

const trial_id = "1";

export const progressTask = task({
  id: `progress-task-${trial_id}`,
  run: async (payload: any, { ctx }) => {
    const totalSteps = 5;

    for (let i = 1; i <= totalSteps; i++) {
      const currentProgress = (i / totalSteps) * 100;

      // Update metadata with the current progress percentage
      await ctx.run.updateMetadata({ progress: currentProgress });

      // Simulate work
      await new Promise((resolve) => setTimeout(resolve, 1000));
    }

    return {
      message: "Task completed successfully",
      progress: 100
    };
  },
});

